head.script:
// 전역변수
scwin.login = $c.data.getMemInfo();
scwin.privAdmin = scwin.login.privAdmin;
scwin.sysAdminYn = scwin.login.sysAdminYn;
scwin.vUserHomeClsCd = scwin.login.userHomeClsCd;
scwin.vLoginCoCd = scwin.login.coCd;
scwin.vLoginCoClsCd = scwin.login.coClsCd;
scwin.isSubCompany = false;
scwin.vEmpNo = $c.data.getMemInfo("empNo");

scwin.txtCoClsCd;
scwin.hid_fixedAsetHistClsCd;

scwin.isFirst = true;

scwin.onpageload = function () {

};

scwin.onUdcCompleted = async function () {

    udc_srchAcctDeptCd3.hide("");
    btn_fileSave.hide("");

    const codeOptions = [
        { grpCd: "FI111", compID: "acb_evidClsCd", opt: { "range": "1" } }
    ];
    $c.data.setCommonCode(codeOptions);

    // $c.gus.cfDisableKey();

    // scwin.f_SearchHeaderCreate();			//조회데이터셋 생성
    dma_evidClsCd.set("00");

    //자산유형 조회
    $c.sbm.execute(sbm_asetPattern);

    // gr_transfer.TitleHeight = 30;
    scwin.f_FieldClear();

    scwin.f_setCompanyInfo();

}

//-------------------------------------------------------------------------
// 자회사 회계 시스템 추가에 따른 설정 
//-------------------------------------------------------------------------
scwin.f_setCompanyInfo = function (e) {

    // 사용자 구분이 자회사('SA')가 아닌 경우, 소속회사를  '동부 EXPRESS'로  Default set
    if (scwin.vUserHomeClsCd != ACConstants.SUBSIDIARY_USER_HOME_CLS_CD) {
        scwin.vLoginCoCd = ACConstants.CO_CD_DONGBU;
        scwin.vLoginCoClsCd = ACConstants.CO_CLS_CD_DONGBU;
    }

    ed_coCd.setValue(scwin.vLoginCoCd);
    scwin.f_PopUpCompanyInfo('T');
}

//-------------------------------------------------------------------------
// 조회 필드 Clear
//-------------------------------------------------------------------------
scwin.f_FieldClear = function () {
    $c.gus.cfInitObjects(tbl_search, [ed_acqDtStDt, ed_acqDtEndDt, ed_procDt]);
    scwin.f_SetSrchDefault();
}

//-------------------------------------------------------------------------
// 조회 기본값 설정
//-------------------------------------------------------------------------
scwin.f_SetSrchDefault = function () {
    ed_acqDtStDt.setValue(WebSquare.date.getCurrentServerDate().substring(0, 6) + "01");
    ed_acqDtEndDt.setValue(WebSquare.date.getCurrentServerDate());
    //ed_procDt.text     = new Date().format("YYYYMMDD");
    ed_acqDtStDt.focus();
}

//-------------------------------------------------------------------------
// 조회
//-------------------------------------------------------------------------
scwin.f_Retrieve = async function () {
    if (!await scwin.f_RetrieveValidate()) {
        return false;
    }

    // 자산이력 구분코드(자산이관):50
    dma_search.set("fixedAsetHistClsCd", ACConstants.ASET_HISTCD_TRANSFER);
    dma_search.set("asetPatternCd", acb_asetPatternCd.getValue());
    dma_search.set("deprCompleteYn", acb_deprCompleteYn.getValue());
    dma_search.set("fixedAsetNo", ed_srchFixedAsetNo.getValue());
    dma_search.set("orgFixedAsetNo", ed_srchOrgFixedAsetNo.getValue());
    dma_search.set("procDt", ed_procDt.getValue());
    dma_search.set("coClsCd", scwin.txtCoClsCd);

    $c.sbm.execute(sbm_search);
}

//-------------------------------------------------------------------------
// 처리일자 변경시 재조회 기능 - 년월만비교(월단위로 누계액을 가져오기 때문에)
//-------------------------------------------------------------------------
scwin.f_checkProcDt = async function () {

    var input_procDt = ed_procDt.getValue();
    var output_procDt = ed_procDt.getValue();

    if (ds_master.getTotalRow() > 0) {
        for (var i = 0; i < 1; i++) {
            var output_procDt = ds_master.getCellData(0, "procDt");
            //alert(output_procDt);
        }
    }

    if (input_procDt != output_procDt) {
        await $c.win.alert("이관일자가 변경되어 재조회 됩니다.");
        scwin.f_Retrieve();
    }
}

//-------------------------------------------------------------------------
// 조회 검증
//-------------------------------------------------------------------------
scwin.f_RetrieveValidate = async function () {
    /*
        if (ds_transfer.CountRow > 0 && ds_transfer.IsUpdated == true) {
            if (cfConfirmMsg(MSG_CM_CRM_005) == false)
                return;
        }
        */

    if ($c.gus.cfIsNull(ed_acqDtStDt.getValue()) && $c.gus.cfIsNull(ed_acqDtEndDt.getValue())
        && $c.gus.cfIsNull(acb_asetPatternCd.getValue())
        && $c.gus.cfIsNull(ed_srchAcctDeptCd.getValue()) && $c.gus.cfIsNull(ed_srchAcctDeptNm.getValue())
        && $c.gus.cfIsNull(ed_srchFixedAsetNo.getValue())) {
        await $c.gus.cfAlertMsg("조회조건을 하나 이상 입력해 주세요.");
        ed_acqDtStDt.focus();
        return false;
    }

    if (!await $c.gus.cfValidate([tbl_search])) {
        return false;
    }

    //취득 일자 체크
    if ($c.gus.cfIsNull(ed_acqDtStDt.getValue()) && !$c.gus.cfIsNull(ed_acqDtEndDt.getValue())) {
        await $c.gus.cfAlertMsg(MSG_CM_WRN_003, ["취득일자"]);
        ed_acqDtStDt.focus();
        return false;
    }

    if (!$c.gus.cfIsNull(ed_acqDtStDt.getValue()) && $c.gus.cfIsNull(ed_acqDtEndDt.getValue())) {
        await $c.gus.cfAlertMsg(MSG_CM_WRN_003, ["취득일자"]);
        ed_acqDtEndDt.focus();
        return false;
    }

    if (!$c.gus.cfIsNull(ed_acqDtStDt.getValue()) && !$c.gus.cfIsNull(ed_acqDtEndDt.getValue())) {
        // if (!$c.gus.cfValidateValue(ed_acqDtEndDt.getValue(),"minDate=" + ed_acqDtStDt.getValue())) {
        if (WebSquare.date.dateDiff(ed_acqDtStDt.getValue(), ed_acqDtEndDt.getValue()) < 0) {
            await $c.gus.cfAlertMsg(MSG_CM_ERR_039);
            ed_acqDtStDt.focus();
            return false;
        }
    }

    // if (!$c.gus.cfIsNull(ed_acqDtStDt.getValue()) && !$c.gus.cfIsNull(ed_acqDtEndDt.getValue())) {
    //     if (!await $c.gus.cfValidateValue(ed_acqDtEndDt.getValue(), "minDate=" + ed_acqDtStDt.getValue())) {
    //         await $c.gus.cfAlertMsg(MSG_CM_ERR_039);
    //         ed_acqDtStDt.focus();
    //         return false;
    //     }
    // }

    return true;
}

//-------------------------------------------------------------------------
// 20121012 by kimseok
// 마감통제 목록조회  
// 회사코드/매각/이관/폐기 일자일자를 기준으로 현재 감가삼각마감정보를 가져온다. 
// 매각의 경우 되므로, 증빙일자가 따로 존재하며, 증빙일자를 기준으로 마감데이터를 조회한다. 
// 감가삼각마감정보가 존재하고, 진행상태코드가, 0:진행중이거나, 2:마감완료의 경우,
// 경고메세지 출력후 처리를 불가능하게 한다. 
//-------------------------------------------------------------------------
scwin.f_CloseControlRetrieve = async function () {

    var coCd = ed_coCd.getValue();                   // 회사코드
    var qryStdt = ed_procDt.getValue().substring(0, 6); // 증빙일자
    var wrkNo = "FI05";                         // 작업번호(FI05:감가삼각마감)

    var condition = "?coCd=" + coCd + "&qryStDt=" + qryStdt + "&wrkNo=" + wrkNo;

    sbm_closeControl.action = "/cm.bc.comnmgnt.closemgnt.RetrieveCloseControlListCMD.do" + condition;
    await $c.sbm.execute(sbm_closeControl);

    //dataSetDebug(ds_closeControl,true);
    // 감가삼각마감정보가 있으며, 
    if (ds_closeControl.getTotalRow() > 0) {
        // 매각일자에 해당하는월이 감가삼각 마감완료 되었거나, 진행중이라면, 매각처리를 불가능하게 한다. 
        // 공통코트[ZZ529:마감진행상태코드], 0:진행중,1:미마감,2:마감완료
        if (ds_closeControl.getCellData(0, "closePrgsStsCd") == "0") {
            await $c.win.alert("[" + qryStdt + "] 월에 감가삼각마감이 진행중입니다.\n이관처리가 불가능합니다. 재경팀의 문의하세요.");
            return false;
        }
        if (ds_closeControl.getCellData(0, "closePrgsStsCd") == "2") {
            await $c.win.alert("[" + qryStdt + "] 월에 감가삼각마감이 마감완료되었습니다.\n이관처리가 불가능합니다. 재경팀의 문의하세요.");
            return false;
        }
        else {
            return true;
        }
    }
    else {
        return true;
    }
}

//-------------------------------------------------------------------------
// 자산증빙 파일업로드 실행하고 저장처리
//-------------------------------------------------------------------------
scwin.f_Save = async function () {
    let fileList = udc_fileUpload.getData();
    if (fileList.length == 0) {
        scwin.uploadComplete();
    } else {
        if (ds_fileUploadGDS.getTotalRow() > 0) {
            var evidClsCd = udc_fileUpload.getData();
            if (evidClsCd == "" || evidClsCd == "00") {
                await $c.win.alert("증빙파일구분을 선택하세요");
                return;
            }
        }
        udc_fileUpload.startFileUpload();
    }
}

scwin.uploadComplete = function () {
    scwin.f_SaveProc();
}

//-------------------------------------------------------------------------
// 저장
//-------------------------------------------------------------------------
scwin.f_SaveProc = async function () {

    var fileList = udc_fileUpload.getData();

    if (ds_transfer.getTotalRow() < 1) {
        await $c.gus.cfAlertMsg(MSG_CM_ERR_056, ["이관자산"]);
        return;
    } else {
        //입력 validation
        if (!await scwin.f_Validation()) {
            return;
        }


        // 마감정보가 마감완료거나 마감중이라면, 진행하지 않는다. 
        if (!await scwin.f_CloseControlRetrieve()) {
            return;
        }


        if (fileList.length != 0) {

            var evidClsCd = acb_evidClsCd.getValue();
            if (evidClsCd == "" || evidClsCd == "00") {
                await $c.win.alert("증빙파일구분을 선택하세요");
                return;
            }
        }

        if (await $c.win.confirm(MSG_CM_CRM_001)) {

            dma_transferDt.set("transferDt", ed_procDt.getValue())

            // dma_evidClsCd.set("evidClsCd",acb_evidClsCd.getValue());
            if (fileList.length != 0) {
                await udc_fileUpload.startFileUpload();
            }
            $c.sbm.execute(sbm_master);

        }
    }
}

//-------------------------------------------------------------------------
// 입력 Validation
//-------------------------------------------------------------------------
scwin.f_Validation = async function () {

    //자산이관 입력 validation
    if (!await scwin.f_TransferValidate()) {
        return false;
    }
    return true;
}

//-------------------------------------------------------------------------
// 자산이관 입력Validation
//-------------------------------------------------------------------------
scwin.f_TransferValidate = async function () {

    for (var i = 0; i < ds_transfer.getTotalRow(); i++) {
        if (ds_transfer.getCellData(i, "acctDeptCd") == ds_transfer.getCellData(i, "tranAfAcctDeptCd")) {
            await $c.gus.cfAlertMsg("이관전 귀속부서와 이관후 귀속부서가 동일합니다.");
            ds_transfer.setRowPosition(i);
            gr_transfer.setFocusedCell(i, "tranAfAcctDeptCd", true);
            return false;
        }

        if (ds_transfer.getCellData(i, "procQty") <= 0) {
            await $c.gus.cfAlertMsg(MSG_CM_WRN_003, ["이관수량"]);
            ds_transfer.setRowPosition(i);
            gr_transfer.setFocusedCell(i, "procQty", true);
            return false;
        }

        if (ds_transfer.getCellData(i, "procQty") > ds_transfer.getCellData(i, "qty")) {
            await $c.gus.cfAlertMsg("이관수량이 수량을 초과하였습니다.");
            ds_transfer.setRowPosition(i);
            gr_transfer.setFocusedCell(i, "procQty", true);
            return false;
        }

        /*if (ds_transfer.NameValue(i,"acqDt") > ed_procDt.text) {
            cfAlertMsg("자산번호 " + ds_transfer.NameString(i,"fixedAsetNo") + " 의 이관일자가 취득일자 이전입니다.");
            gr_master.SetColumn("fixedAsetNo");
            return false;
        }*/

        if (ds_transfer.getCellData(i, "procRate") == "100") {
            if (ds_transfer.getCellData(i, "procQty") != ds_transfer.getCellData(i, "qty")) {
                await $c.gus.cfAlertMsg("비율이 100(%)인경우 수량과 이관수량은 일치해야합니다.");
                gr_transfer.setFocusedCell(i, "procQty", true);
                return false;
            }
        }

        if ((ds_transfer.getCellData(i, "asetPatternNm") == "토지") || (ds_transfer.getCellData(i, "asetPatternNm") == "건물")) {
            if (ds_transfer.getCellData(i, "procQty") != ds_transfer.getCellData(i, "qty")) {
                await $c.gus.cfAlertMsg("토지 및 건물은 부분이관이 불가합니다.");
                gr_transfer.setFocusedCell(i, "procQty", true);
                return false;
            }
        }

        if (ds_transfer.getCellData(i, "tranAfAcctDeptCd") == "") {
            await $c.gus.cfAlertMsg(MSG_CM_WRN_003, ["이관부서코드"]);
            ds_transfer.setRowPosition(i);
            gr_transfer.setFocusedCell(i, "tranAfAcctDeptCd", true);
            return false;
        }

    }
    return true;
}

//-------------------------------------------------------------------------
// 조회 귀속부서코드 팝업
//-------------------------------------------------------------------------
scwin.f_srchDeptPopUp = function (flag) {
    var param = "," + ed_coCd.getValue() + "," + scwin.txtCoClsCd;

    var rtnList = udc_srchAcctDeptCd.cfCommonPopUp(scwin.udc_srchAcctDeptCd_callBack, ed_srchAcctDeptCd.getValue(), ""
        , flag, null, null, null, null
        , param, "410", null, null, null);
}

//-------------------------------------------------------------------------
// 일괄적용 귀속부서코드 팝업
//-------------------------------------------------------------------------
scwin.f_srchDeptPopUp2 = function (flag) {
    var param = "," + ed_coCd.getValue() + "," + scwin.txtCoClsCd;

    var rtnList = udc_srchAcctDeptCd2.cfCommonPopUp(scwin.udc_srchAcctDeptCd2_callBack, ed_acctDeptCd.getValue(), ""
        , flag, null, null, null, null
        , param, "410", null, null, null);
}

scwin.udc_srchAcctDeptCd_callBack = function (rtnList) {

    if (rtnList != null) {
        if (rtnList[0] != "N/A") {
            ed_srchAcctDeptCd.setValue(rtnList[0]);
            ed_srchAcctDeptCd.options.hidVal = rtnList[0];
            ed_srchAcctDeptNm.setValue(rtnList[1]);
        }
    } else {
        ed_srchAcctDeptCd.setValue("");
        ed_srchAcctDeptCd.options.hidVal = "";
        ed_srchAcctDeptNm.setValue("");
    }
}

scwin.udc_srchAcctDeptCd2_callBack = function (rtnList) {

    if (rtnList != null) {
        if (rtnList[0] != "N/A") {
            ed_acctDeptCd.setValue(rtnList[0]);
            ed_acctDeptCd.options.hidVal = rtnList[0];
            ed_acctDeptNm.setValue(rtnList[1]);
        }
    } else {
        ed_acctDeptCd.setValue("");
        ed_acctDeptCd.options.hidVal = "";
        ed_acctDeptNm.setValue("");
    }
}

//-------------------------------------------------------------------------
// 하단으로이동
//-------------------------------------------------------------------------
scwin.f_DownMove = async function (type) {

    var row = gr_master.getAllFocusedRowIndex();

    for (let j = 0; j < row.length; j++) {

        if ((type == 'a') || ((type == 'm'))) {
            if (ds_transfer.getMatchedIndex("fixedAsetNo", ds_master.getCellData(row[j], "fixedAsetNo")).length > 0) {
                $c.gus.cfAlertMsg("자산번호 " + ds_master.getCellData(row[j], "fixedAsetNo") + "는 이미 추가된 행입니다.");
                return;
            }
        }
        ds_transfer.setRowJSON(ds_transfer.getTotalRow(), ds_master.getRowJSON(row[j]));
    }

    // if (type == 'a') {
    //     ds_master.DeleteAll();
    // } else {
    //     ds_master.DeleteMarked();
    // }

    //이동한 다음 row에 focus 설정
    //ds_master.MarkRows(ds_master.RowPosition, ds_master.RowPosition);

    ed_totalRow2.setValue(ds_transfer.getTotalRow());
    // cfShowTotalRows(totalRows2, ds_transfer.CountRow);
}

//-------------------------------------------------------------------------
// 상단으로이동
//-------------------------------------------------------------------------
scwin.f_UpMove = function (type) {

    if ((type == 'a') || ((type == 'm'))) {
        var row = gr_transfer.getAllFocusedRowIndex();
        ds_transfer.removeRows(row);
    }

    ed_totalRow2.setValue(ds_transfer.getTotalRow());
    // cfShowTotalRows(totalRows2, ds_transfer.CountRow);
}

