//-------------------------------------------------------------------------
// 일괄적용함수
//-------------------------------------------------------------------------	
scwin.f_WholeAdoption = async function () {

    if (ed_acctDeptCd.getValue().trim() == "") {
        await $c.win.alert("귀속부서를 입력해주세요");
        return;
    }

    var totalRow = ds_transfer.getTotalRow();
    for (var i = 0; i < totalRow; i++) {

        ds_transfer.setCellData(i, "tranAfAcctDeptCd", ed_acctDeptCd.getValue());
        ds_transfer.setCellData(i, "tranAfAcctDeptNm", ed_acctDeptNm.getValue());
    }
}

//-------------------------------------------------------------------------
// 회사 입력 팝업 
//-------------------------------------------------------------------------
scwin.f_PopUpCompanyInfo = function (pWinCloseTF) {
    scwin.pWinClose = pWinCloseTF;
    var rtnList = udc_companyInfo.cfCommonPopUp(scwin.udc_coCd_callBackFunc
        , ed_coCd.getValue(), ed_coNm.getValue()
        , pWinCloseTF, null, null, null, null
        , null, null, null, null, null);
}

scwin.udc_coCd_callBackFunc = function (rtnList) {
    // SET	 
    if (rtnList != null) {
        if (rtnList[0] == "N/A") return;
        ed_coCd.setValue(rtnList[0]);	// 코드
        ed_coNm.setValue(rtnList[5]); // 회사명 
        ed_coCd.options.hidVal = rtnList[0];  // 히든값
        scwin.txtCoClsCd = rtnList[1];	// 회사구분  

        $c.gus.cfInitObjects([ed_srchAcctDeptCd, ed_srchAcctDeptNm]); // 조회조건 - 귀속부서 
        $c.gus.cfInitObjects([ed_acctDeptCd, ed_acctDeptNm]);     // 이관 - 귀속부서 
    } else {
        ed_coCd.setValue("");
        ed_coNm.setValue("");
        ed_coCd.options.hidVal = "";
        scwin.txtCoClsCd = "";
    }

    if (scwin.txtCoClsCd > ACConstants.CO_CLS_CD_DONGBU) {  	// 자회사 회계 시스템 
        scwin.isSubCompany = true;
    } else {
        scwin.isSubCompany = false;
    }

    if (scwin.isFirst == true) {
        if ('T' == scwin.privAdmin || !scwin.isSubCompany) { // ADMIN 권한이 있는 경우, 동부 EXPRESS 인 경우 
            $c.gus.cfEnableObjects([ed_coCd, ed_coNm, btn_company]);
        } else {
            $c.gus.cfDisableObjects([ed_coCd, ed_coNm, btn_company]);
        }

        scwin.isFirst = false;
    }
}

//-------------------------------------------------------------------------
// 자산이관 데이터셋 헤더 생성
//-------------------------------------------------------------------------
scwin.f_TransferHeaderCreate = function () {
    ds_transfer.removeAll();
    $c.gus.cfCopyDataSetHeader(ds_master, ds_transfer);
}

scwin.udc_companyInfo_onclickEvent = function (e) {
    scwin.f_PopUpCompanyInfo('F');
};

scwin.udc_companyInfo_onblurCodeEvent = function (e) {
    ed_coNm.setValue("");
    scwin.f_PopUpCompanyInfo('T');
};

scwin.udc_srchAcctDeptCd_onclickEvent = function (e) {
    scwin.f_srchDeptPopUp("F");
};

scwin.udc_srchAcctDeptCd_onblurCodeEvent = function (e) {
    scwin.f_srchDeptPopUp("T");
};

scwin.udc_srchAcctDeptCd2_onclickEvent = function (e) {
    scwin.f_srchDeptPopUp2("F");
};

scwin.udc_srchAcctDeptCd2_onblurCodeEvent = function (e) {
