scwin.sbm_search_submitdone = async function (e) {

    if (e.responseJSON.resultDataSet[0].Msg != "FAIL") {

        ed_totalRow.setValue(ds_master.getTotalRow());
        ed_totalRow2.setValue(ds_transfer.getTotalRow());

        scwin.f_TransferHeaderCreate();

        if (ds_master.getTotalRow() == 0) {
            await $c.gus.cfAlertMsg(MSG_CM_WRN_002);
        } else {
            gr_master.focus();
        }

        dma_evidClsCd.set("evidClsCd", "00");
    }
};


