scwin.ds_transfer_oncelldatachange = async function (info) {
    var row = info.rowIndex;
    var colid = info.colID;

    // var colid = gr_transfer.getColumnID(columnIndex)

    if (colid == "procQty") {
        ds_transfer.setCellData(row, "procRate", (Number(ds_transfer.getCellData(row, "procQty")) / Number(ds_transfer.getCellData(row, "qty"))) * 100);

    }

    //수량이 1개인 자산을 부분처리할경우 비율 입력시 수량 소숫점 자동 계산 (부분처리를 위함)
    if (colid == "procRate" && ds_transfer.getCellData(row, "qty") == 1) {

        const factor = Math.pow(10, 3);
        var num = (Number(ds_transfer.getCellData(row, "procRate")) * Number(ds_transfer.getCellData(row, "qty"))) / 100
        var formatNum = Math.floor(num * factor) / factor;

        ds_transfer.setCellData(row, "procQty", formatNum);

    }

    if (colid == "procRate") {

        var procRate = Number(ds_transfer.getCellData(row, "procRate")) / 100;

        if ((ds_transfer.getCellData(row, "asetPatternNm") == "토지" || ds_transfer.getCellData(row, "asetPatternNm") == "건물") &&
            (procRate != 1)) {
            await $c.win.alert("토지 및 건물은 부분이관이 불가합니다.");
            ds_transfer.setCellData(row, "procRate", 0);
            ds_transfer.setCellData(row, "procQty", 0);
        }
        else {
            ds_transfer.setCellData(row, "procAcqAmt", Math.round(Number(ds_transfer.getCellData(row, "acqAmt")) * (procRate)));

            ds_transfer.setCellData(row, "procBefYyProvAmt", Math.round(Number(ds_transfer.getCellData(row, "befYyProvAmt")) * (procRate)));
            ds_transfer.setCellData(row, "procThisYyProvAmt", Math.round(Number(ds_transfer.getCellData(row, "thisYyProvAmt")) * (procRate)));
            ds_transfer.setCellData(row, "procBookAmt", Number(ds_transfer.getCellData(row, "procAcqAmt"))
                - (Number(ds_transfer.getCellData(row, "procBefYyProvAmt")) + Number(ds_transfer.getCellData(row, "procThisYyProvAmt"))));
            ds_transfer.setCellData(row, "procDifferAmt", Number(ds_transfer.getCellData(row, "procBookAmt")));
        }
    }

    // if (colid == "tranAfAcctDeptCd") {
    //     debugger;
    //     if (ds_transfer.getCellData(row, "tranAfAcctDeptCd") == "") {
    //         ds_transfer.setCellData(row, "tranAfAcctDeptNm", "")
    //     } else {
    //         scwin.f_GridPopUp("T");
    //     }
    // }

};

